// Inline timer.h and timer.cpp logic if needed, but simplified for OpenMP translation
// We assume timer.h is available or inline minimal parts if PROFILING/TIMING is used.
// Since the build command is just 'make', we assume the environment provides timer.h/timing.h 
// or we must inline them. The prompt says "If your translated code needs definitions from them, inline the definitions".
// However, to keep it clean and since the original code includes them, we will rely on the includes 
// but ensure the OpenMP logic replaces the OpenCL logic.

// Re-defining timer class inline to ensure compilation if headers are missing in target env
#ifdef PROFILING
class timer {
    public:
               timer(const char *name = 0);
               timer(const char *name, std::ostream &write_on_exit);
               ~timer();
    void       start(), stop();
    void       reset();
    double     getTimeInSeconds();
    private:
    union {
        long long   total_time;
        struct {
            int low, high;
        };
    };
    unsigned long long count;
    const char   *const name;
    std::ostream   *const write_on_exit;
    static double   CPU_speed_in_MHz, get_CPU_speed_in_MHz();
};

std::ostream &operator << (std::ostream &, class timer &);

inline void timer::reset() { total_time = 0; count = 0; }
inline timer::timer(const char *name) : name(name), write_on_exit(0) { reset(); }
inline timer::timer(const char *name, std::ostream &write_on_exit) : name(name), write_on_exit(&write_on_exit) { reset(); }
inline timer::~timer() {}
inline void timer::start() {
#if (defined __GNUC__ || defined __INTEL_COMPILER) && (defined __i386 || defined __x86_64)
    asm volatile ("rdtsc\n\t" "subl %%eax, %0\n\t" "sbbl %%edx, %1" : "+m" (low), "+m" (high) : : "eax", "edx");
#else
    total_time = 0; // Fallback
#endif
}
inline void timer::stop() {
#if (defined __GNUC__ || defined __INTEL_COMPILER) && (defined __i386 || defined __x86_64)
    asm volatile ("rdtsc\n\t" "addl %%eax, %0\n\t" "adcl %%edx, %1" : "+m" (low), "+m" (high) : : "eax", "edx");
#else
    total_time = 1; // Fallback
#endif
    ++ count;
}
inline double timer::getTimeInSeconds() {
    double total = static_cast<double>(total_time);
    double speed = get_CPU_speed_in_MHz();
    if (speed == 0.0) return 0.0;
    return (total / 1000000.0) / speed;
}
double timer::CPU_speed_in_MHz = timer::get_CPU_speed_in_MHz();
double timer::get_CPU_speed_in_MHz() {
#if defined __linux__
    std::ifstream infile("/proc/cpuinfo");
    char buffer[256], *colon;
    while (infile.good()) {
        infile.getline(buffer, 256);
        if (strncmp("cpu MHz", buffer, 7) == 0 && (colon = strchr(buffer, ':')) != 0)
            return atof(colon + 2);
    }
#endif
    return 0.0;
}
#endif

struct Node {
    int starting;
    int no_of_edges;
};

// OpenMP version of BFS_1
void bfs_1_omp(const Node* graph_nodes, const int* graph_edges, char* graph_mask, 
               char* updating_graph_mask, char* graph_visited, int* cost, int no_of_nodes) {
    #pragma omp parallel for
    for (int tid = 0; tid < no_of_nodes; tid++) {
        if (graph_mask[tid]) {
            graph_mask[tid] = false;
            int start = graph_nodes[tid].starting;
            int end = start + graph_nodes[tid].no_of_edges;
            for (int i = start; i < end; i++) {
                int id = graph_edges[i];
                if (!graph_visited[id]) {
                    cost[id] = cost[tid] + 1;
                    updating_graph_mask[id] = true;
                }
            }
        }
    }
}

// OpenMP version of BFS_2
bool bfs_2_omp(char* graph_mask, char* updating_graph_mask, char* graph_visited, int no_of_nodes) {
    bool over = false;
    #pragma omp parallel for
    for (int tid = 0; tid < no_of_nodes; tid++) {
        if (updating_graph_mask[tid]) {
            graph_mask[tid] = true;
            graph_visited[tid] = true;
            updating_graph_mask[tid] = false;
            over = true;
        }
    }
    return over;
}

void run_bfs_cpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size, 
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask, 
                 char *h_graph_visited, int *h_cost_ref) {
    char stop;
    int k = 0;
    do {
        stop = false;
        #pragma omp parallel for
        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (h_graph_mask[tid]) {
                h_graph_mask[tid] = false;
                int start = h_graph_nodes[tid].starting;
                int end = start + h_graph_nodes[tid].no_of_edges;
                for (int i = start; i < end; i++) {
                    int id = h_graph_edges[i];
                    if (!h_graph_visited[id]) {
                        h_cost_ref[id] = h_cost_ref[tid] + 1;
                        h_updating_graph_mask[id] = true;
                    }
                }
            }
        }

        #pragma omp parallel for
        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (h_updating_graph_mask[tid]) {
                h_graph_mask[tid] = true;
                h_graph_visited[tid] = true;
                stop = true;
                h_updating_graph_mask[tid] = false;
            }
        }
        k++;
    } while (stop);
}

void run_bfs_omp(int no_of_nodes, Node *h_graph_nodes, int edge_list_size, 
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask, 
                 char *h_graph_visited, int *h_cost) {

    #ifdef PROFILING
    timer kernel_timer;
    double kernel_time = 0.0;
    kernel_timer.reset();
    kernel_timer.start();
    #endif

    bool h_over;
    do {
        h_over = false;

        bfs_1_omp(h_graph_nodes, h_graph_edges, h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost, no_of_nodes);

        h_over = bfs_2_omp(h_graph_mask, h_updating_graph_mask, h_graph_visited, no_of_nodes);

    } while (h_over);

    #ifdef PROFILING
    kernel_timer.stop();
    kernel_time = kernel_timer.getTimeInSeconds();
    std::cout << "kernel time(s):" << kernel_time << std::endl;
    #endif

    #ifdef TIMING
    printf("Exec: %f\n", kernel_time);
    #endif
}

void Usage(int argc, char**argv) {
    fprintf(stderr, "Usage: %s <input_file> [-p platform] [-d device] [-t gpu(0)/cpu(1)]\n", argv[0]);
}

int main(int argc, char * argv[]) {
    int no_of_nodes;
    int edge_list_size;
    FILE *fp;
    Node* h_graph_nodes;
    char *h_graph_mask, *h_updating_graph_mask, *h_graph_visited;

    try {
        char *input_f;
        if (2 > argc) {
            Usage(argc, argv);
            exit(0);
        }

        input_f = argv[1];
        printf("Reading File\n");

        fp = fopen(input_f, "r");
        if (!fp) {
            printf("Error Reading graph file\n");
            return 0;
        }

        int source = 0;
        fscanf(fp, "%d", &no_of_nodes);

        int num_of_blocks = 1;
        int num_of_threads_per_block = no_of_nodes;
        int MAX_THREADS_PER_BLOCK = 256;

        if (MAX_THREADS_PER_BLOCK < no_of_nodes) {
            num_of_blocks = (int)ceil(no_of_nodes / (double)MAX_THREADS_PER_BLOCK);
            num_of_threads_per_block = MAX_THREADS_PER_BLOCK;
        }

        h_graph_nodes = (Node*) malloc(sizeof(Node) * no_of_nodes);
        h_graph_mask = (char*) malloc(sizeof(char) * no_of_nodes);
        h_updating_graph_mask = (char*) malloc(sizeof(char) * no_of_nodes);
        h_graph_visited = (char*) malloc(sizeof(char) * no_of_nodes);

        int start, edgeno;

        for (int i = 0; i < no_of_nodes; i++) {
            fscanf(fp, "%d %d", &start, &edgeno);
            h_graph_nodes[i].starting = start;
            h_graph_nodes[i].no_of_edges = edgeno;
            h_graph_mask[i] = false;
            h_updating_graph_mask[i] = false;
            h_graph_visited[i] = false;
        }

        fscanf(fp, "%d", &source);
        source = 0;

        h_graph_mask[source] = true;
        h_graph_visited[source] = true;
        fscanf(fp, "%d", &edge_list_size);
        int id, cost;
        int* h_graph_edges = (int*) malloc(sizeof(int) * edge_list_size);
        for (int i = 0; i < edge_list_size; i++) {
            fscanf(fp, "%d", &id);
            fscanf(fp, "%d", &cost);
            h_graph_edges[i] = id;
        }

        if (fp)
            fclose(fp);

        int *h_cost = (int*) malloc(sizeof(int) * no_of_nodes);
        int *h_cost_ref = (int*) malloc(sizeof(int) * no_of_nodes);
        for (int i = 0; i < no_of_nodes; i++) {
            h_cost[i] = -1;
            h_cost_ref[i] = -1;
        }
        h_cost[source] = 0;
        h_cost_ref[source] = 0;

        // Run OpenMP version
        run_bfs_omp(no_of_nodes, h_graph_nodes, edge_list_size, h_graph_edges, h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost);

        // Reset for CPU reference
        for (int i = 0; i < no_of_nodes; i++) {
            h_graph_mask[i] = false;
            h_updating_graph_mask[i] = false;
            h_graph_visited[i] = false;
        }

        source = 0;
        h_graph_mask[source] = true;
        h_graph_visited[source] = true;
        run_bfs_cpu(no_of_nodes, h_graph_nodes, edge_list_size, h_graph_edges, h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost_ref);

        compare_results<int>(h_cost_ref, h_cost, no_of_nodes);

        free(h_graph_nodes);
        free(h_graph_mask);
        free(h_updating_graph_mask);
        free(h_graph_visited);
        free(h_graph_edges);
        free(h_cost);
        free(h_cost_ref);

    } catch (std::string msg) {
        std::cout << "--cambine: exception in main ->" << msg << std::endl;
    }

    return 0;
}
